  ('real-estate-moex-00570', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依房屋稅條例規定，下列敘述何者錯誤？', '["合法登記之工廠供直接生產使用之自有房屋，免徵房屋稅", "受重大災害，毀損面積佔整棟面積五成以上，必須修復始能使用之私有房屋，免徵房屋稅", "房屋標準價格，每三年重行評定一次，並應依其耐用年數予以折舊，按年遞減其價格", "各級政府機關及地方自治機關之公有辦公房屋及其員工宿舍，免徵房屋稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00571', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '關於契稅稅率依契稅條例之規定，下列敘述何者錯誤？', '["買賣契稅為其契價百分之六", "贈與契稅為其契價百分之六", "占有契稅為其契價百分之六", "典權契稅為其契價百分之六"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00572', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權人於出售土地後，依土地稅法規定，下列何種情形得申請就其已納土地增值稅額內， 退還其不足支付新購土地地價之數額？', '["土地所有權人於先購買土地後，自完成移轉登記之日起二年後，始行出售土地者", "其新購土地地價超過原出售土地地價，扣除繳納房地交易所得稅後之餘額者", "自耕之農業用地出售後，於二年內另行購買仍供自耕之農業用地者", "土地出售前一年內，曾供營業使用或出租者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00573', 'real-estate', 'real-estate-moex-109-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地稅法規定，有關地價稅優惠稅率與減免，下列敘述何者錯誤？', '["依都市計畫法劃設並經目的事業主管機關核准供公眾停車使用之停車場用地，按千分之十計徵 地價稅", "經目的事業主管機關核准設立之私立公園、體育場所使用範圍內之土地，免徵地價稅", "公有土地按基本稅率徵收地價稅。但公有土地供公共使用者，免徵地價稅", "都市計畫公共設施保留地，在保留期間仍為建築使用者，除自用住宅用地依第17條之規定外， 統按千分之六計徵地價稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:36+00:00", "source_pdf_sha1": "47ea4d99da30", "answer_pdf_sha1": "e2822ec905db", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
